INSERT INTO public.exercise (id, complexity, description, instructions, level, region, russian_title, short_thumbnail, subcategory, thumbnail, time, title, youtube_video_id) VALUES (1, 'EASY', 'Gluteal warm-up enhances muscle activation, improves stability, and reduces injury risk. This exercise strengthens hip and pelvic muscles, preparing the body for physical activity.', '["Stand upright with feet hip-width apart and knees slightly bent", "Slowly extend one leg backward, keeping your back straight and controlled", "Squeeze the glute muscles, holding the position for a second", "Return your leg to the starting position, maintaining balance", "Repeat 10-15 times for each leg", "For added difficulty, use a resistance band or perform on a raised platform"]', 'BEGINNER', 'HIPS', 'Проминка ягодичного региона', 'https://storage.googleapis.com/banner-ai-saved-images/exercise.png', 'MFR', 'https://storage.googleapis.com/banner-ai-saved-images/exercise-big.png', 5, 'Gluteal Warm-Up', 'gJh03s2HNeo');
